function buildAllIndexNowUrls() {
  const urls = [];
  urls.push('/', '/contact', '/academy/intro', '/academy/all');
  urls.push('/conversation/english', '/conversation/chinese', '/conversation/japanese');
  urls.push('/study-guide', '/engineer-lab', '/video-lesson');
  for (const s of ['math','english','korean','science','social','coding','essay','gsd']) urls.push('/subject/'+s);
  for (const g of ['elementary','middle','high']) urls.push('/grade/'+g);
  for (const [sido, reg] of Object.entries(REGIONS)) {
    const se = SIDO_EN[sido]||sido;
    urls.push('/'+se);
    for (const [ak, area] of Object.entries(reg.areas||{})) {
      const ge = DISTRICT_EN[ak]||ak;
      urls.push(`/${se}/${ge}`);
      for (const d of (area.dongs||[])) {
        const dr = toRoman(d);
        urls.push(`/${se}/${ge}/${dr}`);
        for (const g of ['elementary','middle','high']) {
          for (const sk of Object.keys(SUBJECTS)) {
            urls.push(`/${se}/${ge}/${dr}/${g}/${SUBJECT_EN[sk]||sk}`);
          }
        }
      }
      const gugunSchools = SCHOOL_MAP[se]?.[ak];
      if (gugunSchools) {
        for (const names of Object.values(gugunSchools)) {
          if (!Array.isArray(names)) continue;
          for (const n of names) {
            const sr = toRoman(n);
            urls.push(`/school/${se}/${ge}/${sr}`);
            for (const sk of Object.keys(SUBJECTS)) {
              urls.push(`/school/${se}/${ge}/${sr}/${SUBJECT_EN[sk]||sk}`);
            }
          }
        }
      }
    }
  }
  return urls.map(u => 'https://allcarestudy.com'+u);
}

async function submitIndexNowChunk(urlList) {
  const INDEXNOW_KEY = '82576028bc8743f5869b54199452e4b4';
  const body = JSON.stringify({
    host: 'allcarestudy.com',
    key: INDEXNOW_KEY,
    keyLocation: 'https://allcarestudy.com/' + INDEXNOW_KEY + '.txt',
    urlList
  });
  const headers = {'Content-Type': 'application/json; charset=utf-8'};
  const [naver, bing] = await Promise.all([
    fetch('https://searchadvisor.naver.com/indexnow', { method: 'POST', headers, body }).then(r=>r.status).catch(()=>0),
    fetch('https://api.indexnow.org/indexnow', { method: 'POST', headers, body }).then(r=>r.status).catch(()=>0)
  ]);
  return { naver, bing, count: urlList.length };
}

